import React, { useState } from 'react';
import img from '../img/1000_F_475009987_zwsk4c77x3cTpcI3W1C1LU4pOSyPKaqi.jpg';
import './navbar.css';

const Navbar = () => {
    const [searchTerm, setSearchTerm] = useState('');
    const [isLoggedIn, setIsLoggedIn] = useState(true); // Set to false to test login view

    const handleSearch = () => {
        if (searchTerm.trim()) {
            // Simulate search: Log or filter data (replace with actual logic, e.g., API call or state update)
            console.log('Searching for:', searchTerm);
            alert(`Searching for: ${searchTerm}`); // Demo alert; remove in production
        }
    };

    const handleLogin = () => {
        // Simulate login: Set to true (replace with actual auth logic)
        setIsLoggedIn(true);
    };

    const handleLogout = () => {
        // Simulate logout: Set to false (replace with actual auth logic)
        setIsLoggedIn(false);
    };

    return (
        <nav className="navbar">
            <div className="navbar-left">
                <span className="hospital-name">MediCare <span className="plus">+</span></span>
            </div>
            
            <div className="navbar-center">
                <div className="search-container">
                    <input 
                        type="text" 
                        placeholder="Search patients, records..." 
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        onKeyPress={(e) => e.key === 'Enter' && handleSearch()} // Allow Enter key to search
                    />
                    <button className="search-btn" onClick={handleSearch}>🔍</button>
                </div>
            </div>

            <div className="navbar-right">
                {isLoggedIn ? (
                    <>
                        <div className="notification-icon">
                            🔔 <span className="badgeid">3</span>
                        </div>
                        <div className="user-profile">
                            <img src={img} alt="Admin" className="avatar" />
                            <div className="user-info">
                                <span className="user-name">Dr. Alexander</span>
                                <span className="user-role">Administrator</span>
                                <button onClick={handleLogout} className="logout-btn">Logout</button>
                            </div>
                        </div>
                    </>
                ) : (
                    <button onClick={handleLogin} className="login-btn">Login</button>
                )}
            </div>
        </nav>
    );
};

export default Navbar;
